  ('police-f3743df6-moex-00188', 'police-f3743df6', 'police-f3743df6-moex-113-9c159a92', 'sub-police-f3743df6-04', NULL, 'essay', '依產業創新條例第53條第2項規定，經濟部產業園區管理局甲產業園區服
務中心擬定甲產業園區一般公共設施維護費費率，報由經濟部核定後，公
布於機關網站。該費率針對甲產業園區內閒置土地，加徵 5 倍維護費。乙
為甲產業園區廠商認為5倍維護費過高，並不合理。試問，甲產業園區一般
公共設施維護費費率之法律性質為何？其公布於機關網站是否已踐行發布
程序？（40分）
參考條文
產業創新條例第53條
依第 50 條規定成立之管理機構，得向區內各使用人收取下列費用：1.一般公共設
施維護費。2.污水處理系統使用費。3.其他特定設施之使用費或維護費。
前項各類費用之費率，由管理機構擬訂，產業園區屬中央主管機關開發者，應報中
央主管機關核定；屬直轄市、縣市主管機關、公民營事業開發者，應報直轄市、縣
市主管機關核定。
中央主管機關及直轄市、縣市主管機關開發之產業園區內使用人屆期不繳納第 1 項
之費用者，每逾 2 日按滯納數額加徵百分之 1 滯納金；加徵之滯納金額，以應納
費額之百分之15為限。', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:18+00:00", "source_pdf_sha1": "e25c46bef9e1", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "512", "s": "0409", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "警察法制作業", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
